import type { CircuitBreakerOptions, FetchRequest } from "./types.ts";

// https://developer.mozilla.org/en-US/docs/Web/HTTP/Status
export const defaultCircuitBreakerFailureStatusCodes = [
  408, // Request Timeout
  409, // Conflict
  425, // Too Early (Experimental)
  429, // Too Many Requests
  500, // Internal Server Error
  502, // Bad Gateway
  503, // Service Unavailable
  504, // Gateway Timeout
];

export type CircuitState = "closed" | "open" | "half-open";

export interface CircuitBreakerRecord {
  state: CircuitState;
  consecutiveFailures: number;
  /** Timestamp (`Date.now()`) after which an `open` circuit may move to `half-open`. */
  nextAttempt: number;
  halfOpenInFlight: number;
}

export type CircuitBreakerStore = Map<string, CircuitBreakerRecord>;

export interface ResolvedCircuitBreakerOptions {
  threshold: number;
  cooldown: number;
  halfOpenMaxRequests: number;
  failureStatusCodes: number[];
}

export type CircuitBreakerOutcome = "success" | "failure" | "ignore";

export interface CircuitBreakerMarker {
  key: string;
  options: ResolvedCircuitBreakerOptions;
  halfOpenSlot: boolean;
  finalized: boolean;
}

export function resolveCircuitBreakerOptions(
  option: true | CircuitBreakerOptions
): ResolvedCircuitBreakerOptions {
  const opts = option === true ? {} : option;
  return {
    threshold: opts.threshold ?? 5,
    cooldown: opts.cooldown ?? 30_000,
    halfOpenMaxRequests: opts.halfOpenMaxRequests ?? 1,
    failureStatusCodes:
      opts.failureStatusCodes ?? defaultCircuitBreakerFailureStatusCodes,
  };
}

export function getRequestOrigin(request: FetchRequest): string {
  try {
    if (typeof request === "string") {
      return new URL(request).origin;
    }
    if (request instanceof URL) {
      return request.origin;
    }
    return new URL((request as Request).url).origin;
  } catch {
    return typeof request === "string"
      ? request
      : String((request as Request)?.url ?? request);
  }
}

function getRecord(
  store: CircuitBreakerStore,
  key: string
): CircuitBreakerRecord {
  let record = store.get(key);
  if (!record) {
    record = {
      state: "closed",
      consecutiveFailures: 0,
      nextAttempt: 0,
      halfOpenInFlight: 0,
    };
    store.set(key, record);
  }
  return record;
}

/**
 * Evaluates whether a request against `key` is allowed to proceed.
 * Throws a `FetchError` (fast-fail, no underlying fetch call) when the
 * circuit is open or the half-open probe quota is exceeded.
 */
export function evaluateCircuitBreaker(
  store: CircuitBreakerStore,
  key: string,
  options: ResolvedCircuitBreakerOptions
): CircuitBreakerMarker {
  const record = getRecord(store, key);
  const now = Date.now();

  if (record.state === "open" && now >= record.nextAttempt) {
    record.state = "half-open";
    record.halfOpenInFlight = 0;
  }

  if (record.state === "open") {
    throw new FetchError(`Circuit breaker is open for "${key}"`);
  }

  if (record.state === "half-open") {
    if (record.halfOpenInFlight >= options.halfOpenMaxRequests) {
      throw new FetchError(
        `Circuit breaker is open for "${key}" (half-open probe limit reached)`
      );
    }
    record.halfOpenInFlight++;
    return { key, options, halfOpenSlot: true, finalized: false };
  }

  return { key, options, halfOpenSlot: false, finalized: false };
}

/**
 * Records the outcome of a logical request (including any internal retries)
 * exactly once. Safe to call multiple times; only the first call has effect.
 */
export function finalizeCircuitBreaker(
  store: CircuitBreakerStore,
  marker: CircuitBreakerMarker | undefined,
  outcome: CircuitBreakerOutcome
): void {
  if (!marker || marker.finalized) {
    return;
  }
  marker.finalized = true;

  const record = getRecord(store, marker.key);

  if (outcome === "failure") {
    record.consecutiveFailures++;
    if (record.state === "half-open") {
      record.state = "open";
      record.nextAttempt = Date.now() + marker.options.cooldown;
    } else if (
      record.state === "closed" &&
      record.consecutiveFailures >= marker.options.threshold
    ) {
      record.state = "open";
      record.nextAttempt = Date.now() + marker.options.cooldown;
    }
  } else if (outcome === "success") {
    record.consecutiveFailures = 0;
    if (record.state === "half-open") {
      record.state = "closed";
    }
  }

  if (marker.halfOpenSlot) {
    record.halfOpenInFlight = Math.max(0, record.halfOpenInFlight - 1);
    marker.halfOpenSlot = false;
  }
}
